#!/usr/bin/env python3
"""Heuristic exploration planner: greedy utility + global BFS."""
import os, sys, json, argparse, math, random
from collections import deque
import numpy as np
from cogniplan_env import ExplorationEnv

def euclidean(a, b):
    return math.hypot(a[0]-b[0], a[1]-b[1])

def round_coord(coord):
    return (round(coord[0], 2), round(coord[1], 2))

class HeuristicPlanner:
    def __init__(self, epsilon=0.05):
        self.epsilon = epsilon
        self.nodes_coords = []
        self.coord_to_idx = {}
        self.adj = []
        self.n_nodes = 0

    def reset(self, nodes):
        self.n_nodes = len(nodes)
        self.nodes_coords = []
        self.coord_to_idx.clear()
        for i, nd in enumerate(nodes):
            x = float(nd['coords'][0])
            y = float(nd['coords'][1])
            rc = round_coord((x, y))
            self.nodes_coords.append(rc)
            self.coord_to_idx[rc] = i
        self.adj = [[] for _ in range(self.n_nodes)]
        for i, nd in enumerate(nodes):
            for nb in nd.get('neighbors', []):
                key = round_coord((float(nb[0]), float(nb[1])))
                j = self.coord_to_idx.get(key, -1)
                if j >= 0 and j != i:
                    if j not in self.adj[i]:
                        self.adj[i].append(j)
                    if i not in self.adj[j]:
                        self.adj[j].append(i)

    def bfs_path(self, start_idx, target_idx):
        n = self.n_nodes
        parent = [-1] * n
        q = deque([start_idx])
        visited = [False] * n
        visited[start_idx] = True
        while q:
            u = q.popleft()
            if u == target_idx:
                break
            for v in self.adj[u]:
                if not visited[v]:
                    visited[v] = True
                    parent[v] = u
                    q.append(v)
        return parent

    def reconstruct_path(self, start_idx, target_idx, parent):
        if target_idx < 0 or target_idx >= self.n_nodes:
            return []
        if parent[target_idx] == -1 and target_idx != start_idx:
            return []
        path = []
        cur = target_idx
        safety = 0
        while cur != start_idx and safety < self.n_nodes:
            path.append(cur)
            cur = parent[cur]
            if cur == -1:
                break
            safety += 1
        path.reverse()
        return path

    def get_closest_node_idx(self, pos):
        best_idx = -1
        best_dist = float('inf')
        for i, coord in enumerate(self.nodes_coords):
            d = euclidean(pos, coord)
            if d < best_dist:
                best_dist = d
                best_idx = i
        return best_idx

    def select_action(self, obs, curr_idx, tabu):
        neighbor_coords = obs.get('neighbors', [])
        neighbor_idxs = []
        for nb in neighbor_coords:
            key = round_coord((float(nb[0]), float(nb[1])))
            i = self.coord_to_idx.get(key, -1)
            if i >= 0:
                neighbor_idxs.append(i)
        if not neighbor_idxs:
            return None

        node_utils = []
        for nd in obs['nodes']:
            node_utils.append(nd.get('utility', 0.0))
        if len(node_utils) != self.n_nodes:
            return self.nodes_coords[random.choice(neighbor_idxs)]

        # 1. Greedy neighbor with max utility > 0, not tabu
        best_util = -1
        best_idx = -1
        for ni in neighbor_idxs:
            if ni in tabu:
                continue
            u = node_utils[ni]
            if u > best_util:
                best_util = u
                best_idx = ni
        if best_util > 0 and best_idx >= 0:
            return self.nodes_coords[best_idx]

        # 2. Epsilon random exploration (non-tabu neighbor)
        if random.random() < self.epsilon:
            valid = [i for i in neighbor_idxs if i not in tabu]
            if not valid:
                valid = neighbor_idxs
            return self.nodes_coords[random.choice(valid)]

        # 3. BFS to global maximum utility node (excluding current)
        global_best = -1
        global_best_util = -1
        for i, u in enumerate(node_utils):
            if i != curr_idx and u > global_best_util:
                global_best_util = u
                global_best = i
        if global_best >= 0:
            parent = self.bfs_path(curr_idx, global_best)
            path = self.reconstruct_path(curr_idx, global_best, parent)
            # walk along path, pick first neighbor not tabu
            for p_node in path:
                if p_node in neighbor_idxs and p_node not in tabu:
                    return self.nodes_coords[p_node]
            # fallback: allow tabu neighbor if necessary
            for p_node in path:
                if p_node in neighbor_idxs:
                    return self.nodes_coords[p_node]

        # 4. fallback: any non-tabu neighbor, else any
        valid = [i for i in neighbor_idxs if i not in tabu]
        if not valid:
            valid = neighbor_idxs
        return self.nodes_coords[random.choice(valid)]


def run_episode(env, planner):
    obs = env.reset()
    planner.reset(obs['nodes'])
    prev_pos = (float(obs['robot_pos'][0]), float(obs['robot_pos'][1]))
    curr_idx = planner.get_closest_node_idx(prev_pos)
    tabu = deque(maxlen=3)
    done = False
    step = 0
    while not done and step < 128:
        action = planner.select_action(obs, curr_idx, tabu)
        if action is None:
            break
        tabu.append(curr_idx)
        next_obs, info = env.step(action)
        prev_pos = (float(next_obs['robot_pos'][0]), float(next_obs['robot_pos'][1]))
        curr_idx = planner.get_closest_node_idx(prev_pos)
        obs = next_obs
        done = info.get('done', False)
        step += 1
    metrics = env.get_metrics()
    return {
        'success': 1 if metrics.get('success', False) else 0,
        'explored_rate': float(metrics.get('explored_rate', 0.0)),
        'travel_distance': float(metrics.get('travel_distance', 0.0))
    }


def main():
    parser = argparse.ArgumentParser()
    parser.add_argument('--data_path', type=str, required=True)
    parser.add_argument('--checkpoint', type=str, default=None)
    parser.add_argument('--output', type=str, required=True)
    args = parser.parse_args()

    with open(os.path.join(args.data_path, 'eval_config.json'), 'r') as f:
        eval_config = json.load(f)

    maps_eval_dir = os.path.join(args.data_path, 'maps_eval')
    # collect map files
    map_files = []
    for t in ['room', 'tunnel', 'outdoor']:
        subdir = os.path.join(maps_eval_dir, t)
        if os.path.isdir(subdir):
            for fname in sorted(os.listdir(subdir)):
                if fname.endswith('.png'):
                    map_files.append((t, os.path.join(subdir, fname)))

    planner = HeuristicPlanner(epsilon=0.05)
    per_episode = []
    per_type = {t: {'success': 0, 'count': 0, 'explored_sum': 0.0, 'distance_sum': 0.0} for t in ['room', 'tunnel', 'outdoor']}
    success_count = 0
    total_explored = 0.0
    success_distance_sum = 0.0

    for env_type, mp in map_files:
        env = ExplorationEnv(map_path=mp)
        res = run_episode(env, planner)
        per_episode.append({
            'map_path': '/'.join(mp.split(os.sep)[-2:]),  # like "room/map_001.png"
            'env_type': env_type,
            'success': res['success'],
            'travel_distance': res['travel_distance'],
            'explored_rate': res['explored_rate']
        })
        per_type[env_type]['count'] += 1
        per_type[env_type]['explored_sum'] += res['explored_rate']
        per_type[env_type]['distance_sum'] += res['travel_distance']
        per_type[env_type]['success'] += res['success']
        if res['success']:
            success_count += 1
            success_distance_sum += res['travel_distance']
        total_explored += res['explored_rate']

    total_episodes = len(per_episode)
    results = {
        'explored_rate': total_explored / max(1, total_episodes),
        'travel_distance': success_distance_sum / max(1, success_count) if success_count > 0 else 0.0,
        'success_rate': success_count / max(1, total_episodes),
        'per_episode': per_episode,
        'per_type': {},
        'total_episodes': total_episodes
    }
    for t, d in per_type.items():
        c = d['count']
        sc = d['success']
        results['per_type'][t] = {
            'explored_rate': d['explored_sum'] / max(1, c),
            'travel_distance': d['distance_sum'] / max(1, sc) if sc > 0 else 0.0,
            'success_rate': sc / max(1, c)
        }

    with open(args.output, 'w') as f:
        json.dump(results, f, indent=2)
    print(f"Evaluation done: {total_episodes} episodes, success_rate={results['success_rate']:.4f}")

if __name__ == '__main__':
    main()
